.darma-loader-darma-custom-180 {
  color: var(--loader-color, #0ea5e9);
width: 15px;
aspect-ratio: 1;
position: relative;
}
.darma-loader-darma-custom-180::before,
.darma-loader-darma-custom-180::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
background: currentColor;
}
.darma-loader-darma-custom-180::before {
box-shadow: -26px 0;
animation: darma-loader-darma-custom-180-l10-1 1.5s infinite linear;
}
.darma-loader-darma-custom-180::after {
transform: rotate(0deg) translateX(26px);
animation: darma-loader-darma-custom-180-l10-2 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-180-l10-1 {
50%{transform:translateX(26px)}
}
@keyframes darma-loader-darma-custom-180-l10-2 {
100%{transform:rotate(-360deg) translateX(26px)}
}

